<template>
  <Transition name="modal">
    <div v-if="show" class="modal-overlay" @click="handleOverlayClick">
      <div class="modal-container" :class="[`size-${size}`]" @click.stop>
        <div v-if="showHeader" class="modal-header">
          <h3 class="modal-title">{{ title }}</h3>
          <button v-if="closable" class="close-btn" @click="handleClose">✕</button>
        </div>

        <div class="modal-body">
          <slot />
        </div>

        <div v-if="showFooter" class="modal-footer">
          <slot name="footer">
            <KidButton v-if="showCancel" variant="secondary" @click="handleCancel">
              {{ cancelText }}
            </KidButton>
            <KidButton variant="primary" @click="handleConfirm">
              {{ confirmText }}
            </KidButton>
          </slot>
        </div>
      </div>
    </div>
  </Transition>
</template>

<script setup lang="ts">
import { watch } from 'vue';
import KidButton from './KidButton.vue';

interface Props {
  show: boolean;
  title?: string;
  size?: 'sm' | 'md' | 'lg';
  closable?: boolean;
  showHeader?: boolean;
  showFooter?: boolean;
  showCancel?: boolean;
  confirmText?: string;
  cancelText?: string;
  closeOnClickOverlay?: boolean;
}

const props = withDefaults(defineProps<Props>(), {
  size: 'md',
  closable: true,
  showHeader: true,
  showFooter: true,
  showCancel: true,
  confirmText: '确定',
  cancelText: '取消',
  closeOnClickOverlay: true,
});

const emit = defineEmits<{
  'update:show': [value: boolean];
  confirm: [];
  cancel: [];
  close: [];
}>();

function handleClose() {
  emit('update:show', false);
  emit('close');
}

function handleConfirm() {
  emit('confirm');
}

function handleCancel() {
  emit('cancel');
  handleClose();
}

function handleOverlayClick() {
  if (props.closeOnClickOverlay) {
    handleClose();
  }
}

watch(
  () => props.show,
  (value) => {
    if (value) {
      document.body.style.overflow = 'hidden';
      // 添加 ESC 键监听
      document.addEventListener('keydown', handleEscapeKey);
    } else {
      document.body.style.overflow = '';
      // 移除 ESC 键监听
      document.removeEventListener('keydown', handleEscapeKey);
    }
  }
);

function handleEscapeKey(event: KeyboardEvent) {
  if (event.key === 'Escape' || event.keyCode === 27) {
    if (props.closable && props.closeOnClickOverlay) {
      handleClose();
    }
  }
}
</script>

<style scoped>
.modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.6);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  padding: 20px;
}

.modal-container {
  background: white;
  border-radius: 20px;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
  max-height: 90vh;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.modal-container.size-sm {
  width: 90%;
  max-width: 400px;
}

.modal-container.size-md {
  width: 90%;
  max-width: 600px;
}

.modal-container.size-lg {
  width: 90%;
  max-width: 800px;
}

.modal-header {
  padding: 20px 25px;
  border-bottom: 1px solid #f0f0f0;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.modal-title {
  margin: 0;
  font-size: 1.5rem;
  color: #333;
}

.close-btn {
  background: none;
  border: none;
  font-size: 1.5rem;
  color: #999;
  cursor: pointer;
  padding: 5px;
  transition: color 0.3s;
}

.close-btn:hover {
  color: #FF6B9D;
}

.modal-body {
  padding: 25px;
  overflow-y: auto;
  flex: 1;
}

.modal-footer {
  padding: 20px 25px;
  border-top: 1px solid #f0f0f0;
  display: flex;
  justify-content: flex-end;
  gap: 15px;
}

.modal-enter-active,
.modal-leave-active {
  transition: opacity 0.25s ease;
}

.modal-enter-from,
.modal-leave-to {
  opacity: 0;
}

/* 弹窗容器动画 */
.modal-container {
  animation: modalEnter 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
}

@keyframes modalEnter {
  from {
    opacity: 0;
    transform: translateY(-20px) scale(0.95);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}
</style>
